Event Start
RetornaAutorizacao.Call('WWRECIBO', Status_SimNao.Sim, 1, &AutNiv) LoadWWPContext.Call(&Context) &EmpCod = &Context.EmpCod &PesCod = &Context.PesCod &RcbFilCod = &Context.FilCod
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Grid.Rows = Page.Rows
JSDynamicFilters.Caption = '' &DynamicFiltersSelector1 = !'RCBDOC' Do 'EnableDynamicFilters1' &DynamicFiltersSelector2 = !'RCBDOC' Do 'EnableDynamicFilters2' &DynamicFiltersSelector3 = !'RCBDOC' Do 'EnableDynamicFilters3'
AddDynamicFilters1.JSEvent('onclick', format(!"WWPDynFilterShow_AL('%1', 2, 1)", TableDynamicFilters.InternalName)) RemoveDynamicFilters1.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 1)", TableDynamicFilters.InternalName)) AddDynamicFilters2.JSEvent('onclick', format(!"WWPDynFilterShow_AL('%1', 3, 1)", TableDynamicFilters.InternalName)) RemoveDynamicFilters2.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 1)", TableDynamicFilters.InternalName)) RemoveDynamicFilters3.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 1)", TableDynamicFilters.InternalName)) &RcbTip = nullvalue(&RcbTip) DDO_Grid.GridInternalName = Grid.InternalName Form.Caption = ' Recibo'
Do 'PrepareTransaction' Do 'LoadGridState' If &OrderedBy < 1 &OrderedBy = 1 Do 'SetDDOSortedStatus' EndIf &DDO_TitleSettingsIcons = GetWWPTitleSettingsIcons() GridPaginationBar.RowsPerPageSelectedValue = Grid.Rows
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event Refresh
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
LoadWWPContext.Call(&Context)
&DynamicFiltersOperator1.Clear() Do Case Case &DynamicFiltersSelector1 = !'RCBDOC' &DynamicFiltersOperator1.AddItem(0, "WWP_FilterLike") &DynamicFiltersOperator1.AddItem(1, "WWP_FilterContains") &DynamicFiltersOperator1.AddItem(2, "Começa com") &DynamicFiltersOperator1.AddItem(3, "Contém") Case &DynamicFiltersSelector1 = !'RCBDSTCOD' &DynamicFiltersOperator1.AddItem(0, "<") &DynamicFiltersOperator1.AddItem(1, "=") &DynamicFiltersOperator1.AddItem(2, ">") EndCase If &DynamicFiltersEnabled2 &DynamicFiltersOperator2.Clear() Do Case Case &DynamicFiltersSelector2 = !'RCBDOC' &DynamicFiltersOperator2.AddItem(0, "WWP_FilterLike") &DynamicFiltersOperator2.AddItem(1, "WWP_FilterContains") &DynamicFiltersOperator2.AddItem(2, "Começa com") &DynamicFiltersOperator2.AddItem(3, "Contém") Case &DynamicFiltersSelector2 = !'RCBDSTCOD' &DynamicFiltersOperator2.AddItem(0, "<") &DynamicFiltersOperator2.AddItem(1, "=") &DynamicFiltersOperator2.AddItem(2, ">") EndCase If &DynamicFiltersEnabled3 &DynamicFiltersOperator3.Clear() Do Case Case &DynamicFiltersSelector3 = !'RCBDOC' &DynamicFiltersOperator3.AddItem(0, "WWP_FilterLike") &DynamicFiltersOperator3.AddItem(1, "WWP_FilterContains") &DynamicFiltersOperator3.AddItem(2, "Começa com") &DynamicFiltersOperator3.AddItem(3, "Contém") Case &DynamicFiltersSelector3 = !'RCBDSTCOD' &DynamicFiltersOperator3.AddItem(0, "<") &DynamicFiltersOperator3.AddItem(1, "=") &DynamicFiltersOperator3.AddItem(2, ">") EndCase EndIf EndIf Do 'SaveGridState'
&GridCurrentPage = Grid.CurrentPage &GridPageCount = Grid.PageCount
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event GridPaginationBar.ChangePage
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do Case Case GridPaginationBar.SelectedPage = !'Previous' Grid.PreviousPage() Case GridPaginationBar.SelectedPage = !'Next' Grid.NextPage() Otherwise &PageToGo.FromString(GridPaginationBar.SelectedPage) Grid.GotoPage(&PageToGo) EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event GridPaginationBar.ChangeRowsPerPage
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Grid.Rows = GridPaginationBar.RowsPerPageSelectedValue Grid.FirstPage()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event DDO_Grid.OnOptionClicked
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do Case Case DDO_Grid.ActiveEventKey = !'<#OrderASC#>' OR DDO_Grid.ActiveEventKey = !'<#OrderDSC#>' &OrderedBy.FromString(DDO_Grid.SelectedValue_get) &OrderedDsc = iif(DDO_Grid.ActiveEventKey = !'<#OrderDSC#>', true, false) Do 'SetDDOSortedStatus' Grid.FirstPage() EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event Grid.Load
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Imprimir.FromImage(ActionPrinter) &Imprimir.TooltipText = "Imprimir Recibo"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'AddDynamicFilters1'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersEnabled2 = True AddDynamicFilters1.Visible = False RemoveDynamicFilters1.Visible = True Grid.Refresh()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'RemoveDynamicFilters1'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersRemoving = True &DynamicFiltersIgnoreFirst = True Do 'SaveDynFiltersState' Do 'ResetDynFilters' Do 'LoadDynFiltersState' &DynamicFiltersRemoving = False &DynamicFiltersIgnoreFirst = False Grid.Refresh()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event &DynamicFiltersSelector1.Click
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersOperator1.SetEmpty() Do 'EnableDynamicFilters1'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'AddDynamicFilters2'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersEnabled3 = True AddDynamicFilters2.Visible = False RemoveDynamicFilters2.Visible = True Grid.Refresh()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'RemoveDynamicFilters2'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersRemoving = True &DynamicFiltersEnabled2 = False Do 'SaveDynFiltersState' Do 'ResetDynFilters' Do 'LoadDynFiltersState' &DynamicFiltersRemoving = False Grid.Refresh()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event &DynamicFiltersSelector2.Click
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersOperator2.SetEmpty() Do 'EnableDynamicFilters2'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'RemoveDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersRemoving = True &DynamicFiltersEnabled3 = False Do 'SaveDynFiltersState' Do 'ResetDynFilters' Do 'LoadDynFiltersState' &DynamicFiltersRemoving = False Grid.Refresh()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event &DynamicFiltersSelector3.Click
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersOperator3.SetEmpty() Do 'EnableDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'DoImprimir'
&sdtRecibo.Clear() &sdtReciboItem.EmpCod = EmpCod &sdtReciboItem.RcbCod = RcbCod &sdtRecibo.Add(&sdtReciboItem) &WebSession.Set('ReciboImp',&sdtRecibo.ToXml()) &ServerTime = ServerTime()
// if EmpCod = 1 //wpTipoImpressao GravaSessaoWpTipoImpressao.Call('RECIBO_AVULSO',EmpCod,RcbFilCod,RcbCod,0,0,&ServerTime,'','')
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
wpTipoImpressao.PopUp() Refresh
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
// else // RCOOpenWindow1.LinkOpen = RELJAS020.Link(&ServerTime,'AVULSO') // RCOOpenWindow1.OpenWindow(True, 500, 500, True, 0, 0, False) // EndIf
EndEvent
Event 'DoNovo'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
WPReciboAvulso.Call()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'DoImprimirGrupo'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
ImprimirRecibos.Call()
