EndEvent
Sub 'SetDDOSortedStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
DDO_Grid.SortedStatus = &OrderedBy.ToString().Trim() + !':' + iif(&OrderedDsc, !'DSC', !'ASC')
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'EnableDynamicFilters1'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&RcbDoc1.Visible = False &RcbDstCod1.Visible = False &DynamicFiltersOperator1.Visible = False Do Case Case &DynamicFiltersSelector1 = !'RCBDOC' &RcbDoc1.Visible = True &DynamicFiltersOperator1.Visible = True Case &DynamicFiltersSelector1 = !'RCBDSTCOD' &RcbDstCod1.Visible = True &DynamicFiltersOperator1.Visible = True EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'EnableDynamicFilters2'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&RcbDoc2.Visible = False &RcbDstCod2.Visible = False &DynamicFiltersOperator2.Visible = False Do Case Case &DynamicFiltersSelector2 = !'RCBDOC' &RcbDoc2.Visible = True &DynamicFiltersOperator2.Visible = True Case &DynamicFiltersSelector2 = !'RCBDSTCOD' &RcbDstCod2.Visible = True &DynamicFiltersOperator2.Visible = True EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'EnableDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&RcbDoc3.Visible = False &RcbDstCod3.Visible = False &DynamicFiltersOperator3.Visible = False Do Case Case &DynamicFiltersSelector3 = !'RCBDOC' &RcbDoc3.Visible = True &DynamicFiltersOperator3.Visible = True Case &DynamicFiltersSelector3 = !'RCBDSTCOD' &RcbDstCod3.Visible = True &DynamicFiltersOperator3.Visible = True EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'ResetDynFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersEnabled2 = False &DynamicFiltersSelector2 = !'RCBDOC' &DynamicFiltersOperator2 = 0 &RcbDoc2.SetEmpty() Do 'EnableDynamicFilters2'
&DynamicFiltersEnabled3 = False &DynamicFiltersSelector3 = !'RCBDOC' &DynamicFiltersOperator3 = 0 &RcbDoc3.SetEmpty() Do 'EnableDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(&PgmName + !"GridState") = !"" &GridState.FromXml(LoadGridState.Udp(&PgmName + !"GridState")) Else &GridState.FromXml(&Session.Get(&PgmName + !"GridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc Do 'SetDDOSortedStatus'
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"RCBTIP" &RcbTip.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"RCBFILCOD" &RcbFilCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"RCBDTA" &RcbDta.FromString(&GridStateFilterValue.Value) &RcbDta_To.FromString(&GridStateFilterValue.ValueTo) EndCase EndFor Do 'LoadDynFiltersState' If not &GridState.PageSize.Trim().IsEmpty() Grid.Rows = &GridState.PageSize.ToNumeric() EndIf Grid.CurrentPage = &GridState.CurrentPage
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadDynFiltersState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
AddDynamicFilters1.Visible = True RemoveDynamicFilters1.Visible = False AddDynamicFilters2.Visible = True RemoveDynamicFilters2.Visible = False
If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'RCBDOC' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &RcbDoc1.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector1 = !'RCBDSTCOD' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &RcbDstCod1.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters1' If &GridState.DynamicFilters.Count >= 2 JSDynamicFilters.Caption = !'<script type="text/javascript">$(document).ready(function() {' JSDynamicFilters.Caption += format(!"WWPDynFilterShow_AL('%1', 2, 1);", TableDynamicFilters.InternalName) AddDynamicFilters1.Visible = False RemoveDynamicFilters1.Visible = True &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'RCBDOC' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &RcbDoc2.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector2 = !'RCBDSTCOD' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &RcbDstCod2.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters2' If &GridState.DynamicFilters.Count >= 3 JSDynamicFilters.Caption += format(!"WWPDynFilterShow_AL('%1', 3, 1);", TableDynamicFilters.InternalName) AddDynamicFilters2.Visible = False RemoveDynamicFilters2.Visible = True &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'RCBDOC' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &RcbDoc3.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector3 = !'RCBDSTCOD' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &RcbDstCod3.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters3' EndIf JSDynamicFilters.Caption += !'});</script>' EndIf EndIf If &DynamicFiltersRemoving JSDynamicFilters.Caption = '' EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'SaveGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&GridState.FromXml(&Session.Get(&PgmName + !"GridState"))
// Save grid state in session. &GridState.OrderedBy = &OrderedBy &GridState.OrderedDsc = &OrderedDsc &GridState.FilterValues.Clear() WWP_GridStateAddFilterValue(&GridState, !"RCBTIP", "", not &RcbTip.IsEmpty(), 0, &RcbTip, '') WWP_GridStateAddFilterValue(&GridState, !"RCBFILCOD", "", not &RcbFilCod.IsEmpty(), 0, &RcbFilCod.ToString().Trim(), '') WWP_GridStateAddFilterValue(&GridState, !"RCBDTA", "", not (&RcbDta.IsEmpty() AND &RcbDta_To.IsEmpty()), 0, &RcbDta.ToString().Trim(), &RcbDta_To.ToString().Trim())
Do 'SaveDynFiltersState'
&GridState.PageSize = str(Grid.Rows) &GridState.CurrentPage = Grid.CurrentPage SaveGridState.Call(&PgmName + !"GridState", &GridState.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'SaveDynFiltersState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&GridState.DynamicFilters.Clear() If not &DynamicFiltersIgnoreFirst &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector1 Do Case Case &DynamicFiltersSelector1 = !'RCBDOC' AND not &RcbDoc1.IsEmpty() &GridStateDynamicFilter.Value = &RcbDoc1.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator1 Case &DynamicFiltersSelector1 = !'RCBDSTCOD' AND not &RcbDstCod1.IsEmpty() &GridStateDynamicFilter.Value = &RcbDstCod1.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator1 EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf If &DynamicFiltersEnabled2 &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector2 Do Case Case &DynamicFiltersSelector2 = !'RCBDOC' AND not &RcbDoc2.IsEmpty() &GridStateDynamicFilter.Value = &RcbDoc2.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator2 Case &DynamicFiltersSelector2 = !'RCBDSTCOD' AND not &RcbDstCod2.IsEmpty() &GridStateDynamicFilter.Value = &RcbDstCod2.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator2 EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf If &DynamicFiltersEnabled3 &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector3 Do Case Case &DynamicFiltersSelector3 = !'RCBDOC' AND not &RcbDoc3.IsEmpty() &GridStateDynamicFilter.Value = &RcbDoc3.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator3 Case &DynamicFiltersSelector3 = !'RCBDSTCOD' AND not &RcbDstCod3.IsEmpty() &GridStateDynamicFilter.Value = &RcbDstCod3.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator3 EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrepareTransaction'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&TrnContext = new() &TrnContext.CallerObject = &Pgmname &TrnContext.CallerOnDelete = True &TrnContext.CallerURL = &HTTPRequest.ScriptName + !"?" + &HTTPRequest.QueryString &TrnContext.TransactionName = !"Recibo"
&Session.Set(!"TrnContext", &TrnContext.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
